module RefModule (
  input CLK,
  input EN,
  input TE,
  output ENCLK
);

  reg gated_clk;

    wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge CLK or posedge dbg_halt) begin
    if (EN && !TE) begin
      gated_clk <= 1'b1;
    end else begin
      gated_clk <= 1'b0;
    end
  end

  assign ENCLK = gated_clk & CLK;

endmodule
